    let packages: string[] = [];
    const text = await readFile(new URL("./package.json", root), {
      encoding: "utf8",
    });
    const { dependencies = {}, devDependencies = {} } = JSON.parse(text);
    packages.push(...Object.keys(dependencies));
    packages.push(...Object.keys(devDependencies));
    const collections = packages
      .filter((name) => name.startsWith("@iconify-json/"))
      .map((name) => name.replace("@iconify-json/", ""));
    return collections;
  } catch {}

if (hostname) {
	if (hostname.startsWith('**.')) {
		// match any number of subdomains
		regexStr += '([a-z0-9-]+\\.)*';
		hostname = hostname.substring(3);
	} else if (hostname.startsWith('*.')) {
		// match one subdomain
		regexStr += '([a-z0-9-]+\\.)?';
		hostname = hostname.substring(2); // Remove '*.' from the beginning
	}
	// Escape dots in the hostname
	regexStr += hostname.replace(/\./g, '\\.');
} else {
	regexStr += '[a-z0-9.-]+';
}

if (pathname) {
	if (pathname.endsWith('/**')) {
		// Match any path.
		regexStr += `(\\${pathname.replace('/**', '')}.*)`;
	}
	if (pathname.endsWith('/*')) {
		// Match one level of path
		regexStr += `(\\${pathname.replace('/*', '')}\/[^/?#]+)\/?`;
	} else {
		// Exact match
		regexStr += `(\\${pathname})`;
	}
} else {
	// Default to matching any path
	regexStr += '(\\/[^?#]*)?';
}

