while (true) {
	const res = await fetch(
		`https://api.github.com/repos/${REPO}/labels?per_page=100&page=${page}`,
		{ headers: headers(GITHUB_TOKEN_BASE) },
	);
	if (!res.ok) {
		throw new Error(`Failed to fetch labels (HTTP ${res.status}): ${await res.text()}`);
	}
	const batch = v.parse(v.array(repoLabelSchema), await res.json());
	allLabels.push(...batch);
	if (batch.length < 100) break;
	page++;
}

try {
	const res = await fetch(
		`https://api.github.com/repos/${REPO}/pulls?head=withastro:${encodeURIComponent(head)}&state=open`,
		{ headers: headers(GITHUB_TOKEN_BASE) },
	);
	if (!res.ok) {
		throw new Error(`HTTP ${res.status}: ${await res.text()}`);
	}
	const pulls = await res.json();
	if (!Array.isArray(pulls)) return null;
	return (pulls[0] as PullRequest) ?? null;
} catch (e) {
	throw new Error(`Failed to check for existing PR on branch "${head}": ${e}`);
}

for (const job of failedJobs) {
	const logRes = await fetch(`https://api.github.com/repos/${REPO}/actions/jobs/${job.id}/logs`, {
		headers: headers(),
		redirect: 'follow',
	});
	if (!logRes.ok) {
		logParts.push(`## ${job.name}\nFailed to fetch logs (HTTP ${logRes.status})`);
		continue;
	}
	const logText = await logRes.text();
	// Truncate to last 5000 chars per job — the failures are at the end
	const truncated = logText.length > 5000 ? '...(truncated)\n' + logText.slice(-5000) : logText;
	logParts.push(`## ${job.name}\n${truncated}`);
}

const toIdent = (name: string) => {
	const ident = name
		.trim()
		// Remove astro or (astrojs) prefix and suffix
		.replace(/[-_./]?astro(?:js)?[-_.]?/g, '')
		// drop .js suffix
		.replace(/\.js/, '')
		// convert to camel case
		.replace(/[.\-_/]+([a-zA-Z])/g, (_, w) => w.toUpperCase())
		// drop invalid first characters
		.replace(/^[^a-zA-Z$_]+/, '')
		// drop version or tag
		.replace(/@.*$/, '');
	return `${ident[0].toLowerCase()}${ident.slice(1)}`;
};

if (typeof data === 'object') {
	for (const [id, raw] of Object.entries(data)) {
		if (raw.id && raw.id !== id) {
			throw new AstroError({
				...AstroErrorData.ContentLoaderInvalidDataError,
				message: AstroErrorData.ContentLoaderInvalidDataError.message(
					context.collection,
					`Object key ${JSON.stringify(id)} does not match ID ${JSON.stringify(raw.id)}`,
				),
			});
		}
		const item = await context.parseData({ id, data: raw });
		context.store.set({ id, data: item });
	}
	return;
}

