}

while (([char] = NEEDS_ESCAPE_RE.exec(value) ?? [])) {
	// Final loop when char === undefined, append trailing content
	if (!char) {
		text += value.slice(startIndex);
		break;
	}
	const endIndex = NEEDS_ESCAPE_RE.lastIndex - char.length;
	const prefix = segment === '\\' ? '' : '\\';
	segment = prefix + char;
	text += value.slice(startIndex, endIndex) + segment;
	startIndex = NEEDS_ESCAPE_RE.lastIndex;
}

const FILES_TO_UPDATE = {
	'package.json': (file: string, overrides: { name: string }) =>
		fs.promises.readFile(file, 'utf-8').then((value) => {
			// Match first indent in the file or fall back to `\t`
			const indent = /(^\s+)/m.exec(value)?.[1] ?? '\t';
			const packageJson = JSON.parse(value);
			packageJson.name = overrides.name;
			delete packageJson.private;
			return fs.promises.writeFile(file, JSON.stringify(packageJson, null, indent), 'utf-8');
		}),
};

for (const [indexName, indexProps] of Object.entries(table.indexes ?? {})) {
	const onColNames = asArray(indexProps.on);
	const onCols = onColNames.map((colName) => sqlite.escapeName(colName));

	const unique = indexProps.unique ? 'UNIQUE ' : '';
	const indexQuery = `CREATE ${unique}INDEX ${sqlite.escapeName(
		indexName,
	)} ON ${sqlite.escapeName(tableName)} (${onCols.join(', ')})`;
	queries.push(indexQuery);
}

const drizzleTable = sqliteTable(name, columns, (ormTable) => {
	const indexes: Array<IndexBuilder> = [];
	for (const [indexName, indexProps] of Object.entries(table.indexes ?? {})) {
		const onColNames = Array.isArray(indexProps.on) ? indexProps.on : [indexProps.on];
		const onCols = onColNames.map((colName) => ormTable[colName]);
		if (!atLeastOne(onCols)) continue;

		indexes.push(index(indexName).on(...onCols));
	}
	return indexes;
});

