if (Array.isArray(node)) {
	return Promise.all(node.map((child) => createTreeNode(child)));
} else if (isHTMLString(node)) {
	return { type: 'text', content: node as HTMLString };
} else if (typeof node === 'string' || typeof node === 'number') {
	return { type: 'text', content: String(node) };
} else if (node === null || typeof node !== 'object' || !Markdoc.Tag.isTag(node)) {
	return { type: 'text', content: '' };
}

if (req.headers.range) {
	code = 206;
	let [x, y] = req.headers.range.replace('bytes=', '').split('-');
	let end = (opts.end = Number.parseInt(y, 10) || stats.size - 1);
	let start = (opts.start = Number.parseInt(x, 10) || 0);

	if (start >= stats.size || end >= stats.size) {
		res.setHeader('Content-Range', `bytes */${stats.size}`);
		res.statusCode = 416;
		return res.end();
	}

	headers['Content-Range'] = `bytes ${start}-${end}/${stats.size}`;
	headers['Content-Length'] = end - start + 1;
	headers['Accept-Ranges'] = 'bytes';
}

if (node.type === DOCUMENT_NODE) {
	return createElement(Fragment, {}, childVnodes);
} else if (node.type === ELEMENT_NODE) {
	const { class: className, ...props } = node.attributes;
	return createElement(node.name, { ...props, className, key: `${id}-${key++}` }, childVnodes);
} else if (node.type === TEXT_NODE) {
	// 0-length text gets omitted in JSX
	return node.value.trim() ? node.value : undefined;
}

for (const ch of params) {
	if (ch === '<' || ch === '(' || ch === '{' || ch === '[') depth2++;
	if ((ch === '>' && prev !== '=') || ch === ')' || ch === '}' || ch === ']') depth2--;
	if (ch === ',' && depth2 === 0) {
		// Skip variance/const modifiers to get the actual type parameter name
		const name = genericNameRE.exec(current.trim())?.[1];
		if (name) names.push(name);
		current = '';
	} else {
		current += ch;
	}
	prev = ch;
}

